fn labeled_fields(doc: &apcrp_Document) -> Vec<(&str, &str)> {
    doc.spans
        .iter()
        .filter(|s| s.kind == apcrp_SpanKind::LabeledField)
        .map(|s| (s.label.as_deref().unwrap(), s.text.as_str()))
        .collect()
}

fn section_headers(doc: &apcrp_Document) -> Vec<&str> {
